import React from "react";
import { Toolbar as PrimeToolbar } from "primereact/toolbar";
import { Button, Flex, KitsInputText } from "../../../_compat";
import type {IToolbarProps} from "@lmb-it/kitsconcerto-types";
import {useLanguage} from "../../../_compat";



const TreeViewToolbar = <T,>({
                                                               props,
                                                               filterValue,
                                                               setFilterValue,
                                                               treeRef,
                                                               selectedNode,
                                                               expandAll,
                                                               collapseAll,
                                                               onAddNode,
                                                               onAddNodeItem,
                                                               onDeleteNode,
                                                               onEditNode,
                                                               build
                                                           }:IToolbarProps<T>) => {
    const {t} = useLanguage();
    const {
        expendableControls,
        serverSide,
        text,
        rules,
        hideDisabledButton
    } = props;

    // Logic from original Toolbar.tsx
    const itemButton =
        (rules?.allowIndependentItem && rules?.addItem) ||
        (rules?.addItem && !!selectedNode && !selectedNode.data?.isItem);

    const categoryButton =
        (rules?.addCategory && !selectedNode) ||
        (rules?.addSubCategory && !!selectedNode && !selectedNode.data?.isItem);

    const deleteButton =
        !!selectedNode &&
        ((rules?.deleteCategory &&
                !selectedNode.data?.isItem &&
                !selectedNode.data?.parentId) ||
            (rules?.deleteSubCategory &&
                !selectedNode.data?.isItem &&
                !!selectedNode.data?.parentId) ||
            (rules?.deleteItem && !!selectedNode.data?.isItem));

    const editButton =
        !!selectedNode &&
        ((rules?.updateCategory &&
                !selectedNode.data?.isItem &&
                !selectedNode.data?.parentId) ||
            (rules?.updateSubCategory &&
                !selectedNode.data?.isItem &&
                !!selectedNode.data?.parentId) ||
            (rules?.updateItem && !!selectedNode.data?.isItem));

    const startContent = (
        <Flex flexDirection={"row"} gap={4} alignItems={"center"} w={'full'} justifyContent={'space-between'}>
            <KitsInputText
                leftAddon={<i className={"pi pi-search"}></i>}
                id={"tree-view-filter"}
                value={filterValue}
                onChange={(e) => {
                    setFilterValue(e.target.value);
                    treeRef?.filter?.(e.target.value);
                }}
            />
        </Flex>
    );

    const centerContent = (
        <Flex flexDirection={"row"} gap={4}>
            {!!expendableControls && (
                <>
                    <Button
                        type="button"
                        icon="pi pi-arrow-up-right-and-arrow-down-left-from-center"
                        style={{ w: "40px !important", h: "40px !important" }}
                        onClick={expandAll}
                    />
                    <Button
                        type="button"
                        icon="pi pi-arrow-down-left-and-arrow-up-right-to-center"
                        style={{ w: "40px !important", h: "40px !important" }}
                        onClick={collapseAll}
                    />
                </>
            )}

            {!!serverSide?.listFetcher && (
                <Button
                    type="button"
                    icon="pi pi-refresh"
                    onClick={build}
                    style={{ w: "40px !important", h: "40px !important" }}
                />
            )}
        </Flex>
    );

    const endContent = (
        <Flex
            w={'full'} justifyContent={'space-between'}
            flexDirection={["row", "row", "row", "row", "row"]}
            position={["fixed", "fixed", "fixed", "fixed", "relative"]}
            bottom={[50, 50, 50, 50, 0]}
            right={[50, 50, 50, 50, 0]}
            gap={4}
        >
            {((!hideDisabledButton && !categoryButton) || categoryButton) && (
                <Button
                    type="button"
                    icon="pi pi-plus"
                    disabled={!categoryButton}
                    tooltip={text?.addNode ?? t("addCategory")}
                    style={{ w: "40px !important", h: "40px !important" }}
                    onClick={() => onAddNode(selectedNode?.key)}
                    tooltipOptions={{ position: "top" }}
                />
            )}
            {((!hideDisabledButton && !itemButton) || itemButton) && (
                <Button
                    type="button"
                    severity={"secondary"}
                    disabled={!itemButton}
                    icon="pi pi-plus"
                    tooltip={text?.addItem ?? t("addItem")}
                    style={{ w: "40px !important", h: "40px !important" }}
                    onClick={() => onAddNodeItem(selectedNode?.key)}
                    tooltipOptions={{ position: "top" }}
                />
            )}
            {((!hideDisabledButton && !deleteButton) || deleteButton) && (
                <Button
                    type="button"
                    severity={"danger"}
                    disabled={!deleteButton}
                    icon="pi pi-trash"
                    tooltip={text?.deleteNode ?? t("delete")}
                    style={{ w: "40px !important", h: "40px !important" }}
                    onClick={() => onDeleteNode(selectedNode?.key)}
                    tooltipOptions={{ position: "top" }}
                />
            )}
            {((!hideDisabledButton && !editButton) || editButton) && (
                <Button
                    type="button"
                    severity={"secondary"}
                    disabled={!editButton}
                    icon="pi pi-pencil"
                    tooltip={text?.editNode ?? t("edit")}
                    style={{ w: "40px !important", h: "40px !important" }}
                    onClick={() => onEditNode(selectedNode?.key)}
                    tooltipOptions={{ position: "top" }}
                />
            )}
        </Flex>
    );

    return (
        <PrimeToolbar
            start={startContent}
            center={centerContent}
            end={endContent}
            style={{ width: "100%" }}
            className={"border-noround-bottom"}
        />
    );
}

export default TreeViewToolbar;
